diff --git a/src/auth/refresh.go b/src/auth/refresh.go
+func (s *Service) RefreshToken(ctx context.Context, old string) (string, error) {
+    claims, err := s.verifier.Verify(old)
+    if err != nil {
+        return "", ErrTokenInvalid
+    }
+    return s.issuer.Issue(claims.Subject)
+}
